16	pub use self::or::Or;
17	
18	/// Trait for async functions that can be used to handle requests.
19	///
20	/// This trait is similar to [`Handler`] but rather than taking the request it takes the extracted
21	/// inputs.
22	///
23	/// The drawbacks of this trait is that you cannot apply middleware to individual handlers like you
24	/// can with [`Handler::layer`].
25	pub trait HandlerCallWithExtractors<T, S>: Sized {
26	    /// The type of future calling this handler returns.
27	    type Future: Future<Output = Response> + Send + 'static;
28	
29	    /// Call the handler with the extracted inputs.
30	    fn call(self, extractors: T, state: S) -> <Self as HandlerCallWithExtractors<T, S>>::Future;
31	
32	    /// Convert this `HandlerCallWithExtractors` into [`Handler`].
33	    fn into_handler(self) -> IntoHandler<Self, T, S> {
34	        IntoHandler {
35	            handler: self,
36	            _marker: PhantomData,
37	        }
38	    }
39	
40	    /// Chain two handlers together, running the second one if the first one rejects.
41	    ///
42	    /// Note that this only moves to the next handler if an extractor fails. The response from
43	    /// handlers are not considered.
44	    ///
45	    /// # Example
46	    ///
47	    /// ```
48	    /// use axum_extra::handler::HandlerCallWithExtractors;
49	    /// use axum::{
50	    ///     Router,
51	    ///     routing::get,
52	    ///     extract::FromRequestParts,
53	    /// };
54	    ///
55	    /// // handlers for varying levels of access
56	    /// async fn admin(admin: AdminPermissions) {
57	    ///     // request came from an admin
58	    /// }
59	    ///
60	    /// async fn user(user: User) {
61	    ///     // we have a `User`
62	    /// }
63	    ///
64	    /// async fn guest() {
65	    ///     // `AdminPermissions` and `User` failed, so we're just a guest
66	    /// }
67	    ///
68	    /// // extractors for checking permissions
69	    /// struct AdminPermissions {}
70	    ///
71	    /// impl<S> FromRequestParts<S> for AdminPermissions
72	    /// where
73	    ///     S: Send + Sync,
74	    /// {
75	    ///     // check for admin permissions...
76	    ///     # type Rejection = ();
77	    ///     # async fn from_request_parts(parts: &mut http::request::Parts, state: &S) -> Result<Self, Self::Rejection> {
78	    ///     #     todo!()
79	    ///     # }
80	    /// }
81	    ///
82	    /// struct User {}
83	    ///
84	    /// impl<S> FromRequestParts<S> for User
85	    /// where
86	    ///     S: Send + Sync,
87	    /// {
88	    ///     // check for a logged in user...
89	    ///     # type Rejection = ();
90	    ///     # async fn from_request_parts(parts: &mut http::request::Parts, state: &S) -> Result<Self, Self::Rejection> {
91	    ///     #     todo!()
92	    ///     # }
93	    /// }
94	    ///
95	    /// let app = Router::new().route(
96	    ///     "/users/{id}",
97	    ///     get(
98	    ///         // first try `admin`, if that rejects run `user`, finally falling back
99	    ///         // to `guest`
100	    ///         admin.or(user).or(guest)
101	    ///     )
102	    /// );
