391	    fn fallback_endpoint(self, endpoint: Endpoint<S>) -> Self {
392	        // TODO make this better.
393	        // We need the returned `Service` to be `Clone` and the function inside `service_fn` to be
394	        // `FnMut` so instead of just using the owned service, we do this trick with `Option`. We
395	        // know this will be called just once so it's fine. We're doing that so that we avoid one
396	        // clone inside `oneshot_inner` so that the `Router` and subsequently the `State` is not
397	        // cloned too much.
398	        tap_inner!(self, mut this => {
399	            _ = this.path_router.route_endpoint(
400	                "/",
401	                endpoint.clone().layer(
402	                    layer_fn(
403	                        |service: Route| {
404	                            let mut service = Some(service);
405	                            service_fn(
406	                                #[cfg_attr(not(feature = "matched-path"), allow(unused_mut))]
407	                                move |mut request: Request| {
408	                                    #[cfg(feature = "matched-path")]
409	                                    request.extensions_mut().remove::<MatchedPath>();
410	                                    let route = take_route_or_internal_error(&mut service);
411	                                    route.oneshot_inner_owned(request)
412	                                }
413	                            )
414	                        }
415	                    )
416	                )
417	            );
418	
419	            _ = this.path_router.route_endpoint(
420	                FALLBACK_PARAM_PATH,
421	                endpoint.layer(
422	                    layer_fn(
423	                        |service: Route| {
424	                            let mut service = Some(service);
425	                            service_fn(
426	                                #[cfg_attr(not(feature = "matched-path"), allow(unused_mut))]
427	                                move |mut request: Request| {
428	                                    #[cfg(feature = "matched-path")]
429	                                    request.extensions_mut().remove::<MatchedPath>();
430	                                    let route = take_route_or_internal_error(&mut service);
431	                                    route.oneshot_inner_owned(request)
432	                                }
433	                            )
434	                        }
435	                    )
436	                )
437	            );
438	
439	            this.default_fallback = false;
440	        })
441	    }
