443	    #[doc = include_str!("../docs/routing/with_state.md")]
444	    pub fn with_state<S2>(self, state: S) -> Router<S2> {
445	        map_inner!(self, this => RouterInner {
446	            path_router: this.path_router.with_state(state.clone()),
