452	    pub(crate) fn call_with_state(&self, req: Request, state: S) -> RouteFuture<Infallible> {
453	        let (req, state) = match self.inner.path_router.call_with_state(req, state) {
454	            Ok(future) => return future,
455	            Err((req, state)) => (req, state),
456	        };
457	
458	        self.inner
459	            .catch_all_fallback
460	            .clone()
461	            .call_with_state(req, state)
462	    }
463	
464	    /// Convert the router into a borrowed [`Service`] with a fixed request body type, to aid type
465	    /// inference.
466	    ///
467	    /// In some cases when calling methods from [`tower::ServiceExt`] on a [`Router`] you might get
468	    /// type inference errors along the lines of
469	    ///
470	    /// ```not_rust
471	    /// let response = router.ready().await?.call(request).await?;
472	    ///                       ^^^^^ cannot infer type for type parameter `B`
473	    /// ```
474	    ///
475	    /// This happens because `Router` implements [`Service`] with `impl<B> Service<Request<B>> for Router<()>`.
476	    ///
477	    /// For example:
478	    ///
479	    /// ```compile_fail
480	    /// use axum::{
481	    ///     Router,
482	    ///     routing::get,
483	    ///     http::Request,
484	    ///     body::Body,
485	    /// };
486	    /// use tower::{Service, ServiceExt};
487	    ///
488	    /// # async fn async_main() -> Result<(), Box<dyn std::error::Error>> {
489	    /// let mut router = Router::new().route("/", get(|| async {}));
490	    /// let request = Request::new(Body::empty());
491	    /// let response = router.ready().await?.call(request).await?;
492	    /// # Ok(())
493	    /// # }
494	    /// ```
495	    ///
496	    /// Calling `Router::as_service` fixes that:
497	    ///
498	    /// ```
499	    /// use axum::{
500	    ///     Router,
501	    ///     routing::get,
502	    ///     http::Request,
503	    ///     body::Body,
504	    /// };
505	    /// use tower::{Service, ServiceExt};
506	    ///
507	    /// # async fn async_main() -> Result<(), Box<dyn std::error::Error>> {
508	    /// let mut router = Router::new().route("/", get(|| async {}));
509	    /// let request = Request::new(Body::empty());
510	    /// let response = router.as_service().ready().await?.call(request).await?;
511	    /// # Ok(())
512	    /// # }
513	    /// ```
514	    ///
515	    /// This is mainly used when calling `Router` in tests. It shouldn't be necessary when running
516	    /// the `Router` normally via [`Router::into_make_service`].
517	    pub fn as_service<B>(&mut self) -> RouterAsService<'_, B, S> {
518	        RouterAsService {
