769	            Self::Default(inner) => Self::Default(inner.clone()),
770	            Self::Service(inner) => Self::Service(inner.clone()),
771	            Self::BoxedHandler(inner) => Self::BoxedHandler(inner.clone()),
772	        }
773	    }
774	}
