778	        match self {
779	            Self::Default(inner) => f.debug_tuple("Default").field(inner).finish(),
780	            Self::Service(inner) => f.debug_tuple("Service").field(inner).finish(),
781	            Self::BoxedHandler(_) => f.debug_tuple("BoxedHandler").finish(),
