600	    let hyper_executor = HyperExecutor(executor.clone());
601	    executor.execute(async move {
602	        #[allow(unused_mut)]
603	        let mut builder = Builder::new(hyper_executor);
604	
605	        // Enable Hyper's default HTTP/1 request header timeout.
606	        #[cfg(feature = "http1")]
