609	        // CONNECT protocol needed for HTTP/2 websockets
610	        #[cfg(feature = "http2")]
611	        builder.http2().enable_connect_protocol();
612	
613	        let mut conn = pin!(builder.serve_connection_with_upgrades(io, hyper_service));
614	        let mut signal_closed = pin!(signal_tx.closed().fuse());
