    id: RouteId,
    route_id_to_path: &HashMap<RouteId, Arc<str>>,
    extensions: &mut http::Extensions,
) {
    let Some(matched_path) = route_id_to_path.get(&id) else {
        #[cfg(debug_assertions)]
        panic!("should always have a matched path for a route id");
